import express, { Request, Response, NextFunction } from 'express';
import { body, validationResult } from 'express-validator';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { UserRepository } from './repositories/UserRepository';
import { CreateUserDTO, UserResponseDTO } from './types';

const router = express.Router();
const JWT_SECRET = process.env.JWT_SECRET!;

router.post(
  '/users',
  [
    body('email').isEmail().normalizeEmail(),
    body('password').isLength({ min: 8 }).withMessage('Password must be at least 8 chars'),
    body('name').trim().notEmpty()
  ],
  async (req: Request, res: Response, next: NextFunction) => {
    try {
      const errors = validationResult(req);
      if (!errors.isEmpty()) {
        return res.status(400).json({ errors: errors.array() });
      }

      const dto: CreateUserDTO = req.body;
      const existingUser = await UserRepository.findByEmail(dto.email);
      if (existingUser) {
        return res.status(409).json({ error: 'Email already registered' });
      }

      const hashedPassword = await bcrypt.hash(dto.password, 12);
      const user = await UserRepository.create({ ...dto, password: hashedPassword });

      const token = jwt.sign({ userId: user.id }, JWT_SECRET, { expiresIn: '7d' });
      const response: UserResponseDTO = { id: user.id, email: user.email, name: user.name };

      res.status(201).json({ user: response, token });
    } catch (error) {
      next(error);
    }
  }
);

export default router;

