interface PaginationParams {
  page: number;
  limit: number;
}

interface ProductFilters {
  category?: string;
  minPrice?: number;
  maxPrice?: number;
}

interface SortOptions {
  field: 'price' | 'name' | 'createdAt';
  direction: 'asc' | 'desc';
}

async function listProducts(
  pagination: PaginationParams,
  filters: ProductFilters,
  sort: SortOptions
): Promise<{ data: Product[]; total: number; page: number; totalPages: number }> {
  const { page, limit } = pagination;
  const offset = (page - 1) * limit;

  const query = db('products')
    .select('*')
    .where((builder) => {
      if (filters.category) builder.where('category', filters.category);
      if (filters.minPrice) builder.where('price', '>=', filters.minPrice);
      if (filters.maxPrice) builder.where('price', '<=', filters.maxPrice);
    })
    .orderBy(sort.field, sort.direction)
    .limit(limit)
    .offset(offset);

  const [data, [{ total }]] = await Promise.all([
    query,
    db('products').count('* as total').where(/* same filters */)
  ]);

  return { data, total, page, totalPages: Math.ceil(total / limit) };
}

