import { Request, Response, NextFunction } from 'express';
import jwt, { JwtPayload } from 'jsonwebtoken';

interface AuthRequest extends Request {
  user?: JwtPayload;
}

const JWT_SECRET = process.env.JWT_SECRET!;
const ACCESS_TOKEN_EXPIRY = '15m';
const REFRESH_TOKEN_EXPIRY = '7d';

const tokenBlacklist = new Set<string>();

export function authMiddleware(req: AuthRequest, res: Response, next: NextFunction): void {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    res.status(401).json({ error: 'No token provided' });
    return;
  }

  const token = authHeader.split(' ')[1];

  if (tokenBlacklist.has(token)) {
    res.status(401).json({ error: 'Token revoked' });
    return;
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET) as JwtPayload;
    req.user = payload;
    next();
  } catch (error) {
    if (error instanceof jwt.TokenExpiredError) {
      res.status(401).json({ error: 'Token expired', code: 'TOKEN_EXPIRED' });
    } else {
      res.status(401).json({ error: 'Invalid token' });
    }
  }
}

export function refreshToken(oldToken: string): { accessToken: string; refreshToken: string } {
  if (tokenBlacklist.has(oldToken)) {
    throw new Error('Token already used');
  }
  tokenBlacklist.add(oldToken);

  const payload = jwt.verify(oldToken, JWT_SECRET, { ignoreExpiration: true }) as JwtPayload;
  return {
    accessToken: jwt.sign({ userId: payload.userId }, JWT_SECRET, { expiresIn: ACCESS_TOKEN_EXPIRY }),
    refreshToken: jwt.sign({ userId: payload.userId }, JWT_SECRET, { expiresIn: REFRESH_TOKEN_EXPIRY })
  };
}

export function logout(token: string): void {
  tokenBlacklist.add(token);
}

