import { Pool } from 'pg';
import * as fs from 'fs';
import * as path from 'path';

interface Migration {
  version: string;
  name: string;
  up: string;
  down: string;
  appliedAt?: Date;
}

class MigrationManager {
  private pool: Pool;
  private migrationsDir: string;

  constructor(pool: Pool, migrationsDir: string) {
    this.pool = pool;
    this.migrationsDir = migrationsDir;
  }

  async initialize(): Promise<void> {
    await this.pool.query(`
      CREATE TABLE IF NOT EXISTS migrations (
        version VARCHAR(255) PRIMARY KEY,
        name VARCHAR(255) NOT NULL,
        applied_at TIMESTAMP DEFAULT NOW()
      )
    `);
  }

  async getAppliedMigrations(): Promise<string[]> {
    const result = await this.pool.query('SELECT version FROM migrations ORDER BY version');
    return result.rows.map(r => r.version);
  }

  async getPendingMigrations(): Promise<Migration[]> {
    const applied = await this.getAppliedMigrations();
    const files = fs.readdirSync(this.migrationsDir).filter(f => f.endsWith('.sql'));

    const migrations: Migration[] = [];
    for (const file of files) {
      const [version, ...nameParts] = file.replace('.sql', '').split('_');
      if (!applied.includes(version)) {
        const content = fs.readFileSync(path.join(this.migrationsDir, file), 'utf-8');
        const [up, down] = content.split('-- DOWN').map(s => s.trim());
        migrations.push({ version, name: nameParts.join('_'), up, down });
      }
    }
    return migrations.sort((a, b) => a.version.localeCompare(b.version));
  }

  async migrateUp(): Promise<void> {
    const pending = await this.getPendingMigrations();
    const client = await this.pool.connect();

    try {
      await client.query('BEGIN');
      for (const migration of pending) {
        await client.query(migration.up);
        await client.query('INSERT INTO migrations (version, name) VALUES ($1, $2)', 
          [migration.version, migration.name]);
        console.log(`Applied: ${migration.version}_${migration.name}`);
      }
      await client.query('COMMIT');
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async migrateDown(version: string): Promise<void> {
    const applied = await this.getAppliedMigrations();
    if (!applied.includes(version)) {
      throw new Error(`Migration ${version} not applied`);
    }

    const client = await this.pool.connect();
    try {
      await client.query('BEGIN');
      const result = await client.query('SELECT name, up FROM migrations WHERE version = $1', [version]);
      const migration = result.rows[0];

      // Read down migration
      const files = fs.readdirSync(this.migrationsDir);
      const file = files.find(f => f.startsWith(version));
      if (file) {
        const content = fs.readFileSync(path.join(this.migrationsDir, file), 'utf-8');
        const down = content.split('-- DOWN')[1]?.trim();
        if (down) {
          await client.query(down);
        }
      }

      await client.query('DELETE FROM migrations WHERE version = $1', [version]);
      await client.query('COMMIT');
    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }
}

