import { Server as HTTPServer } from 'http';
import { WebSocketServer, WebSocket } from 'ws';

interface Client {
  id: string;
  ws: WebSocket;
  userId?: string;
  subscriptions: Set<string>;
}

class NotificationServer {
  private wss: WebSocketServer;
  private clients: Map<string, Client> = new Map();

  constructor(server: HTTPServer) {
    this.wss = new WebSocketServer({ server, path: '/ws/notifications' });
    this.wss.on('connection', this.handleConnection.bind(this));
  }

  private generateClientId(): string {
    return `client_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
  }

  private handleConnection(ws: WebSocket): void {
    const clientId = this.generateClientId();
    const client: Client = { id: clientId, ws, subscriptions: new Set() };
    this.clients.set(clientId, client);

    ws.on('message', (data) => this.handleMessage(client, data.toString()));
    ws.on('close', () => this.handleDisconnect(clientId));
    ws.on('error', (error) => console.error(`Client ${clientId} error:`, error));

    ws.send(JSON.stringify({ type: 'CONNECTED', clientId }));
  }

  private handleMessage(client: Client, data: string): void {
    try {
      const message = JSON.parse(data);

      switch (message.type) {
        case 'AUTH':
          client.userId = message.userId;
          client.ws.send(JSON.stringify({ type: 'AUTH_OK' }));
          break;
        case 'SUBSCRIBE':
          client.subscriptions.add(message.channel);
          break;
        case 'UNSUBSCRIBE':
          client.subscriptions.delete(message.channel);
          break;
      }
    } catch (error) {
      client.ws.send(JSON.stringify({ type: 'ERROR', message: 'Invalid message format' }));
    }
  }

  private handleDisconnect(clientId: string): void {
    this.clients.delete(clientId);
    console.log(`Client ${clientId} disconnected`);
  }

  async publish(channel: string, payload: object): Promise<void> {
    const message = JSON.stringify({ type: 'NOTIFICATION', channel, payload, timestamp: Date.now() });

    for (const client of this.clients.values()) {
      if (client.subscriptions.has(channel) && client.ws.readyState === WebSocket.OPEN) {
        client.ws.send(message);
      }
    }
  }

  async sendToUser(userId: string, payload: object): Promise<void> {
    for (const client of this.clients.values()) {
      if (client.userId === userId && client.ws.readyState === WebSocket.OPEN) {
        client.ws.send(JSON.stringify({ type: 'DIRECT', payload }));
      }
    }
  }

  getStats(): { clients: number; connections: number } {
    return {
      clients: this.clients.size,
      connections: this.wss.clients.size
    };
  }
}

