import Redis from 'ioredis';
import { promisify } from 'util';

interface CacheOptions {
  ttl?: number;
  namespace?: string;
}

class CacheService {
  private redis: Redis;
  private defaultTTL: number = 3600;

  constructor(redis: Redis, defaultTTL: number = 3600) {
    this.redis = redis;
    this.defaultTTL = defaultTTL;
  }

  private buildKey(namespace: string, key: string): string {
    return `${namespace}:${key}`;
  }

  async get<T>(namespace: string, key: string): Promise<T | null> {
    const fullKey = this.buildKey(namespace, key);
    const data = await this.redis.get(fullKey);
    return data ? JSON.parse(data) : null;
  }

  async set<T>(namespace: string, key: string, value: T, options?: CacheOptions): Promise<void> {
    const fullKey = this.buildKey(namespace, key);
    const ttl = options?.ttl ?? this.defaultTTL;
    await this.redis.setex(fullKey, ttl, JSON.stringify(value));
  }

  async delete(namespace: string, key: string): Promise<void> {
    await this.redis.del(this.buildKey(namespace, key));
  }

  async invalidatePattern(pattern: string): Promise<void> {
    const keys = await this.redis.keys(pattern);
    if (keys.length > 0) {
      await this.redis.del(...keys);
    }
  }

  async getOrSet<T>(
    namespace: string,
    key: string,
    factory: () => Promise<T>,
    options?: CacheOptions
  ): Promise<T> {
    const cached = await this.get<T>(namespace, key);
    if (cached !== null) {
      return cached;
    }

    const value = await factory();
    await this.set(namespace, key, value, options);
    return value;
  }

  async getStats(namespace: string): Promise<{ keys: number; ttl: number }> {
    const pattern = `${namespace}:*`;
    const keys = await this.redis.keys(pattern);
    const ttl = await this.redis.ttl(keys[0] ?? '');
    return { keys: keys.length, ttl };
  }
}

// Cache-aside repository pattern
export function withCache<T, Args extends any[]>(
  repository: (...args: Args) => Promise<T>,
  cache: CacheService,
  namespace: string,
  keyResolver: (...args: Args) => string,
  ttl?: number
): (...args: Args) => Promise<T> {
  return async (...args: Args): Promise<T> => {
    const cacheKey = keyResolver(...args);
    const cached = await cache.get<T>(namespace, cacheKey);
    if (cached) return cached;

    const result = await repository(...args);
    await cache.set(namespace, cacheKey, result, { ttl });
    return result;
  };
}

