import { Request, Response, NextFunction } from 'express';
import Redis from 'ioredis';

interface RateLimitConfig {
  windowMs: number;
  maxRequests: number;
  keyGenerator?: (req: Request) => string;
}

class SlidingWindowRateLimiter {
  private redis: Redis;
  private config: RateLimitConfig;

  constructor(redis: Redis, config: RateLimitConfig) {
    this.redis = redis;
    this.config = config;
  }

  private getKey(req: Request): string {
    const customKey = this.config.keyGenerator?.(req);
    return customKey ?? `ratelimit:${req.ip}`;
  }

  async checkLimit(req: Request): Promise<{ allowed: boolean; remaining: number; resetAt: number }> {
    const key = this.getKey(req);
    const now = Date.now();
    const windowStart = now - this.config.windowMs;
    const redisKey = `rl:${key}`;

    const multi = this.redis.multi();

    // Remove old entries outside the window
    multi.zremrangebyscore(redisKey, 0, windowStart);

    // Count current requests in window
    multi.zcard(redisKey);

    // Add current request
    multi.zadd(redisKey, now, `${now}:${Math.random()}`);

    // Set expiry on the key
    multi.expire(redisKey, Math.ceil(this.config.windowMs / 1000) + 1);

    const results = await multi.exec();
    const requestCount = results?.[1]?.[1] as number ?? 0;

    const allowed = requestCount < this.config.maxRequests;
    const remaining = Math.max(0, this.config.maxRequests - requestCount - 1);
    const resetAt = now + this.config.windowMs;

    return { allowed, remaining, resetAt };
  }

  middleware() {
    return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
      try {
        const { allowed, remaining, resetAt } = await this.checkLimit(req);

        res.set({
          'X-RateLimit-Limit': this.config.maxRequests.toString(),
          'X-RateLimit-Remaining': remaining.toString(),
          'X-RateLimit-Reset': new Date(resetAt).toISOString()
        });

        if (!allowed) {
          res.status(429).json({
            error: 'Too many requests',
            retryAfter: Math.ceil((resetAt - Date.now()) / 1000)
          });
          return;
        }

        next();
      } catch (error) {
        console.error('Rate limiter error:', error);
        next(); // Fail open to not block legitimate traffic
      }
    };
  }
}

