import { Queue, Worker, Job, QueueEvents } from 'bullmq';
import Redis from 'ioredis';

interface JobData {
  type: string;
  payload: Record<string, any>;
  userId?: string;
}

interface JobResult {
  success: boolean;
  output?: any;
  error?: string;
}

class JobQueueService {
  private connection: Redis;
  private queues: Map<string, Queue> = new Map();
  private workers: Map<string, Worker> = new Map();

  constructor(redisUrl: string) {
    this.connection = new Redis(redisUrl, { maxRetriesPerRequest: null });
  }

  createQueue(name: string): Queue {
    if (this.queues.has(name)) {
      return this.queues.get(name)!;
    }

    const queue = new Queue(name, { connection: this.connection });
    this.queues.set(name, queue);
    return queue;
  }

  async addJob<T extends JobData>(
    queueName: string,
    jobName: string,
    data: T,
    options?: { priority?: number; attempts?: number; backoff?: number }
  ): Promise<string> {
    const queue = this.createQueue(queueName);
    const job = await queue.add(jobName, data, {
      priority: options?.priority ?? 1,
      attempts: options?.attempts ?? 3,
      backoff: {
        type: 'exponential',
        delay: options?.backoff ?? 2000
      },
      removeOnComplete: { count: 100 },
      removeOnFail: { count: 500 }
    });
    return job.id!;
  }

  createWorker<T extends JobData>(
    queueName: string,
    processor: (job: Job<T>) => Promise<JobResult>
  ): Worker {
    if (this.workers.has(queueName)) {
      return this.workers.get(queueName)!;
    }

    const worker = new Worker<T, JobResult>(
      queueName,
      processor,
      { connection: this.connection, concurrency: 5 }
    );

    worker.on('completed', (job, result) => {
      console.log(`Job ${job.id} completed:`, result);
    });

    worker.on('failed', (job, error) => {
      console.error(`Job ${job?.id} failed:`, error.message);
    });

    this.workers.set(queueName, worker);
    return worker;
  }

  async getJobStatus(queueName: string, jobId: string): Promise<Job['attemptsMade'] extends any ? {
    status: string;
    progress: number;
    attemptsMade: number;
    finishedOn?: number;
  } : never> {
    const queue = this.createQueue(queueName);
    const job = await queue.getJob(jobId);
    if (!job) return null;

    const state = await job.getState();
    return {
      status: state,
      progress: job.progress as number,
      attemptsMade: job.attemptsMade,
      finishedOn: job.finishedOn ?? undefined
    };
  }

  async pause(queueName: string): Promise<void> {
    const queue = this.createQueue(queueName);
    await queue.pause();
  }

  async resume(queueName: string): Promise<void> {
    const queue = this.createQueue(queueName);
    await queue.resume();
  }

  async shutdown(): Promise<void> {
    await Promise.all([
      ...Array.from(this.queues.values()).map(q => q.close()),
      ...Array.from(this.workers.values()).map(w => w.close())
    ]);
    await this.connection.quit();
  }
}

