import { gql } from 'apollo-server-express';
import DataLoader from 'dataloader';
import { Pool } from 'pg';

interface Context {
  userLoader: DataLoader<string, User>;
  postsLoader: DataLoader<string, Post[]>;
  pool: Pool;
}

interface User {
  id: string;
  name: string;
  email: string;
}

interface Post {
  id: string;
  title: string;
  authorId: string;
}

export const typeDefs = gql`
  type User {
    id: ID!
    name: String!
    email: String!
    posts: [Post!]!
  }

  type Post {
    id: ID!
    title: String!
    author: User!
  }

  type Query {
    user(id: ID!): User
    users: [User!]!
    post(id: ID!): Post
  }
`;

// Batch function for users (prevents N+1)
async function batchUsers(ids: readonly string[]): Promise<User[]> {
  const result = await ctx.pool.query(
    'SELECT id, name, email FROM users WHERE id = ANY($1)',
    [ids]
  );

  const userMap = new Map(result.rows.map(u => [u.id, u]));
  return ids.map(id => userMap.get(id) ?? null);
}

// Batch function for posts by author
async function batchPostsByAuthor(authorIds: readonly string[]): Promise<Post[][]> {
  const result = await ctx.pool.query(
    'SELECT id, title, author_id FROM posts WHERE author_id = ANY($1)',
    [authorIds]
  );

  const postsByAuthor = new Map<string, Post[]>();
  for (const row of result.rows) {
    const posts = postsByAuthor.get(row.author_id) ?? [];
    posts.push({ id: row.id, title: row.title, authorId: row.author_id });
    postsByAuthor.set(row.author_id, posts);
  }

  return authorIds.map(id => postsByAuthor.get(id) ?? []);
}

export const resolvers = {
  Query: {
    user: (_: unknown, { id }: { id: string }, context: Context) => {
      return context.userLoader.load(id);
    },
    users: async (_: unknown, __: unknown, context: Context) => {
      const result = await context.pool.query('SELECT id FROM users');
      return context.userLoader.loadMany(result.rows.map(r => r.id));
    },
    post: async (_: unknown, { id }: { id: string }, context: Context) => {
      const result = await context.pool.query('SELECT id, title, author_id FROM posts WHERE id = $1', [id]);
      return result.rows[0] ? { ...result.rows[0], authorId: result.rows[0].author_id } : null;
    }
  },
  User: {
    posts: (user: User, _: unknown, context: Context) => {
      return context.postsLoader.load(user.id);
    }
  },
  Post: {
    author: (post: Post, _: unknown, context: Context) => {
      return context.userLoader.load(post.authorId);
    }
  }
};

// Context factory
export function createContext(pool: Pool): Context {
  return {
    userLoader: new DataLoader(batchUsers, { maxBatchSize: 100 }),
    postsLoader: new DataLoader(batchPostsByAuthor, { maxBatchSize: 100 }),
    pool
  };
}

